import{_ as e,c as o,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"クイックスタート: Plannotator入門 | plannotator","description":"Plannotatorのクイックスタート方法を学びます。5分以内にコア機能を理解し、Claude CodeまたはOpenCodeプラグインのインストールと設定を完了します。","frontmatter":{"title":"クイックスタート: Plannotator入門 | plannotator","sidebarTitle":"5分でクイックスタート","subtitle":"クイックスタート: Plannotator入門","description":"Plannotatorのクイックスタート方法を学びます。5分以内にコア機能を理解し、Claude CodeまたはOpenCodeプラグインのインストールと設定を完了します。","order":1},"headers":[],"relativePath":"ja/backnotprop/plannotator/start/index.md","filePath":"ja/backnotprop/plannotator/start/index.md"}'),l={name:"ja/backnotprop/plannotator/start/index.md"};function r(d,a,i,s,c,p){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="クイックスタート" tabindex="-1">クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;クイックスタート&quot;">​</a></h1><p>この章では、Plannotatorをゼロから使い始める方法を案内します。Plannotatorとは何か、どのような問題を解決できるかを理解し、お使いのAI Coding Agent（Claude CodeまたはOpenCode）でインストールと設定を完了します。</p><h2 id="この章の内容" tabindex="-1">この章の内容 <a class="header-anchor" href="#この章の内容" aria-label="Permalink to &quot;この章の内容&quot;">​</a></h2><div class="grid-cards"><h3 id="クイックスタート-1" tabindex="-1"><a href="./getting-started/">クイックスタート</a> <a class="header-anchor" href="#クイックスタート-1" aria-label="Permalink to &quot;[クイックスタート](./getting-started/)&quot;">​</a></h3><p>Plannotatorのコア機能と使用シナリオを理解し、5分以内に初回体験を完了します。すべての新規ユーザーの入門第一課として最適です。</p><h3 id="claude-codeプラグインのインストール" tabindex="-1"><a href="./installation-claude-code/">Claude Codeプラグインのインストール</a> <a class="header-anchor" href="#claude-codeプラグインのインストール" aria-label="Permalink to &quot;[Claude Codeプラグインのインストール](./installation-claude-code/)&quot;">​</a></h3><p>Claude CodeでPlannotatorプラグインをインストールして設定します。プラグインシステムと手動Hookの2つの方法をサポートし、ローカルとリモート環境の設定をカバーします。</p><h3 id="opencodeプラグインのインストール" tabindex="-1"><a href="./installation-opencode/">OpenCodeプラグインのインストール</a> <a class="header-anchor" href="#opencodeプラグインのインストール" aria-label="Permalink to &quot;[OpenCodeプラグインのインストール](./installation-opencode/)&quot;">​</a></h3><p>OpenCodeでPlannotatorプラグインをインストールして設定し、<code>submit_plan</code>ツールと<code>/plannotator-review</code>コマンドを有効にします。</p></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推奨順序</p><ol><li><strong>まず<a href="./getting-started/">クイックスタート</a>を読む</strong>：Plannotatorとは何か、何ができるかを理解し、全体像を把握します</li><li><strong>次にインストールチュートリアルを選択</strong>：お使いのAI Coding Agentに応じたインストールガイドを選びます <ul><li>Claude Codeを使用 → <a href="./installation-claude-code/">Claude Codeプラグインのインストール</a></li><li>OpenCodeを使用 → <a href="./installation-opencode/">OpenCodeプラグインのインストール</a></li></ul></li></ol></div><p>インストールが完了したら、Plannotatorを使用してプランレビューとコードレビューを開始できます。</p><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了したら、**<a href="./../platforms/">プラットフォーム機能</a>**に進んで、プランレビューとコードレビューの完全な使い方を習得します：</p><ul><li>プランレビューの基本：承認、却下、コメントの追加</li><li>画像アノテーション：プランにスクリーンショットを添付してアノテーションを追加</li><li>コードレビュー：Git diffの可視化、行レベルのコメント追加</li></ul>',10)])])}const C=e(l,[["render",r]]);export{u as __pageData,C as default};
